import React, { useMemo, useState, useEffect, useCallback } from 'react';
import { useTable, useSortBy, usePagination } from 'react-table';
import './PurchaseFunc.css';

const Stocks = ({ apiBaseUrl }) => {
  const [materials, setMaterials] = useState([]);
  const [purchases, setPurchases] = useState([]);
  const [locations, setLocations] = useState([]);
  const [outflows, setOutflows] = useState([]);
  const [selectedLocation, setSelectedLocation] = useState('');
  const [globalFilterOne, setGlobalFilterOne] = useState('');
  const [globalFilterTwo, setGlobalFilterTwo] = useState('');

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${authToken}`,
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [materialResponse, purchaseResponse, locationResponse, outflowsResponse] = await Promise.all([
          fetchAPI(`${apiBaseUrl}/materiallist`),
          fetchAPI(`${apiBaseUrl}/PurchasesAPI`),
          fetchAPI(`${apiBaseUrl}/LocationsAPI`),
          fetchAPI(`${apiBaseUrl}/outflowsAPI`),
        ]);
        setMaterials(materialResponse);
        setPurchases(purchaseResponse);
        setLocations(locationResponse);
        setOutflows(outflowsResponse);
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };
    fetchData();
  }, [apiBaseUrl, fetchAPI]);

  const calculateFIFO = useCallback((materialId, location, width = null) => {
    let remainingQuantity = 0;
    let totalCost = 0;

    const filteredPurchases = purchases
      .filter(
        (purchase) =>
          purchase.materialid === materialId &&
          purchase.location === location &&
          (width ? purchase.width === width : !purchase.width)
      )
      .sort((a, b) => new Date(a.date) - new Date(b.date)); // FIFO sorting

    const totalOutflows = outflows
      .filter(
        (outflow) =>
          outflow.materialid === materialId &&
          outflow.location === location &&
          (width ? outflow.width === width : !outflow.width)
      )
      .reduce((sum, outflow) => sum + parseFloat(outflow.quantity), 0);

    for (const purchase of filteredPurchases) {
      const purchaseQuantity = parseFloat(purchase.quantity);
      const purchasePrice = parseFloat(purchase.price);

      if (totalOutflows <= purchaseQuantity) {
        remainingQuantity += purchaseQuantity - totalOutflows;
        totalCost += (purchaseQuantity - totalOutflows) * purchasePrice;
        break;
      } else {
        totalCost += purchaseQuantity * purchasePrice;
        remainingQuantity += purchaseQuantity;
        totalOutflows -= purchaseQuantity;
      }
    }

    return { remainingQuantity, totalCost };
  }, [purchases, outflows]);

  const filteredData = useMemo(() => {
    const uniqueMaterialIds = [];
    return purchases
      .filter((purchase) => purchase.location === parseInt(selectedLocation, 10))
      .filter((purchase) => {
        if (!purchase.width && uniqueMaterialIds.includes(purchase.materialid)) {
          return false;
        }
        if (!purchase.width) uniqueMaterialIds.push(purchase.materialid);
        return true;
      });
  }, [purchases, selectedLocation]);

  const totalCostOfStock = useMemo(() => {
    return filteredData.reduce((sum, row) => {
      const { totalCost } = calculateFIFO(row.materialid, parseInt(selectedLocation, 10), row.width);
      return sum + totalCost;
    }, 0).toFixed(2);
  }, [filteredData, calculateFIFO, selectedLocation]);

  const columns = useMemo(
    () => [
      { Header: 'Material ID', accessor: 'materialid' },
      {
        Header: 'Material Name',
        accessor: (row) => {
          const material = materials.find((m) => m.matid === row.materialid);
          return material ? material.name : 'Material not found';
        },
      },
      { Header: 'Width', accessor: 'width' },
      {
        Header: 'Remaining Quantity',
        accessor: (row) => {
          const { remainingQuantity } = calculateFIFO(row.materialid, parseInt(selectedLocation, 10), row.width);
          return remainingQuantity.toFixed(2);
        },
      },
      {
        Header: 'Total Cost',
        accessor: (row) => {
          const { totalCost } = calculateFIFO(row.materialid, parseInt(selectedLocation, 10), row.width);
          return `${totalCost.toFixed(2)} €`;
        },
      },
    ],
    [materials, calculateFIFO, selectedLocation]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    pageCount,
  } = useTable(
    {
      columns,
      data: filteredData,
      initialState: { pageIndex: 0, pageSize: 10 },
    },
    useSortBy,
    usePagination
  );

  return (
    <div className="container">
      <div className="form-group">
        <label>Location:</label>
        <select value={selectedLocation} onChange={(e) => setSelectedLocation(e.target.value)}>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>

      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>

      <div className="pagination">
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <span>
          Page {pageIndex + 1} of {pageCount}
        </span>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => gotoPage(Number(e.target.value) - 1)}
            style={{ width: '50px' }}
          />
        </span>
        <select value={pageSize} onChange={(e) => setPageSize(Number(e.target.value))}>
          {[10, 25, 50].map((size) => (
            <option key={size} value={size}>
              Show {size}
            </option>
          ))}
        </select>
      </div>

      <div className="total-cost">
        <strong>Total Cost of Stock:</strong> {`${totalCostOfStock} €`}
      </div>
    </div>
  );
};

export default Stocks;
